const AdminNotificationsSender: React.FC<{ addNotification: (msg: string) => void }> = ({ addNotification }) => {
    const [title, setTitle] = useState('');
    const [message, setMessage] = useState('');

    const handleSend = () => {
        if(!title.trim() || !message.trim()) {
            alert('يرجى كتابة عنوان ورسالة الإشعار');
            return;
        }
        addNotification(`تم إرسال الإشعار: "${title}" إلى جميع المستخدمين بنجاح!`);
        setTitle('');
        setMessage('');
    };

    return (
        <div className="p-6 space-y-6 dark:bg-slate-900 h-full">
            <div className="bg-white dark:bg-gray-800 rounded-3xl p-8 shadow-sm border border-gray-100 dark:border-gray-700 max-w-2xl mx-auto">
                <div className="flex items-center justify-end gap-3 mb-8">
                    <h2 className="text-2xl font-bold dark:text-gray-100">إرسال إشعار عام</h2>
                    <div className="w-12 h-12 bg-purple-100 dark:bg-purple-900/30 rounded-full flex items-center justify-center text-purple-600 dark:text-purple-400">
                        <BellIcon className="w-6 h-6" />
                    </div>
                </div>

                <div className="space-y-5">
                    <div>
                        <label className="block text-right text-sm font-bold text-gray-700 dark:text-gray-300 mb-2">عنوان الإشعار</label>
                        <input 
                            type="text" 
                            value={title}
                            onChange={(e) => setTitle(e.target.value)}
                            placeholder="مثال: خصومات الجمعة البيضاء!" 
                            className="w-full p-4 bg-gray-50 dark:bg-gray-700 border border-gray-200 dark:border-gray-600 rounded-2xl text-right focus:ring-2 focus:ring-primary outline-none dark:text-white transition-all"
                        />
                    </div>

                    <div>
                        <label className="block text-right text-sm font-bold text-gray-700 dark:text-gray-300 mb-2">نص الرسالة</label>
                        <textarea 
                            value={message}
                            onChange={(e) => setMessage(e.target.value)}
                            placeholder="اكتب نص الإشعار هنا..." 
                            className="w-full p-4 h-40 bg-gray-50 dark:bg-gray-700 border border-gray-200 dark:border-gray-600 rounded-2xl text-right focus:ring-2 focus:ring-primary outline-none resize-none dark:text-white transition-all"
                        ></textarea>
                    </div>

                    <div className="bg-yellow-50 dark:bg-yellow-900/20 border border-yellow-200 dark:border-yellow-800 p-4 rounded-xl text-sm text-yellow-800 dark:text-yellow-200 text-right flex items-center justify-end gap-2">
                        <span>سيتم إرسال هذا الإشعار إلى جميع المستخدمين المسجلين في التطبيق فوراً.</span>
                        <i className="fa-solid fa-circle-info text-lg"></i>
                    </div>

                    <button 
                        onClick={handleSend}
                        className="w-full bg-primary text-white font-bold py-4 rounded-xl shadow-lg hover:bg-primary/90 transition-all flex items-center justify-center gap-2 transform active:scale-98"
                    >
                        <SendIcon className="w-5 h-5" />
                        إرسال الإشعار
                    </button>
                </div>
            </div>
        </div>
    );
};

