// Sidebar Item Component
const SidebarItem: React.FC<{
    icon: React.ElementType;
    label: string;
    isActive: boolean;
    onClick: () => void;
    badgeCount?: number;
}> = ({ icon: Icon, label, isActive, onClick, badgeCount }) => (
    <button
        onClick={onClick}
        className={`w-full flex items-center justify-between p-3 rounded-xl mb-1 transition-all duration-200 group ${
            isActive 
            ? 'bg-primary text-white shadow-md shadow-primary/30' 
            : 'text-gray-600 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-gray-800'
        }`}
    >
        <div className="flex items-center gap-3">
            <Icon className={`w-5 h-5 ${isActive ? 'text-white' : 'text-gray-500 dark:text-gray-400 group-hover:text-primary'}`} strokeWidth={2} />
            <span className={`font-bold text-sm ${isActive ? 'text-white' : ''}`}>{label}</span>
        </div>
        {badgeCount !== undefined && badgeCount > 0 && (
            <span className={`text-[10px] font-bold px-2 py-0.5 rounded-full ${isActive ? 'bg-white/20 text-white' : 'bg-red-100 text-red-600'}`}>
                {badgeCount > 99 ? '99+' : badgeCount}
            </span>
        )}
    </button>
);

const AdminDashboardPage: React.FC<AdminDashboardPageProps> = ({
  products, onAddProduct, onUpdateProduct, onDeleteProduct, orders, users, customers, 
  onUpdateOrderStatus, onDeleteUser, withdrawalRequests, onProcessWithdrawal, 
  addNotification, faqItems, siteSettings, onSetFaqItems, onUpdateSiteSettings, 
  categories, onSetCategories, onAdminOrderClick, tickets, onUpdateTicketThreadStatus, 
  onAddTicketMessage, onOpenTicketChat, setHeaderConfig, coupons, onAddCoupon, 
  onUpdateCoupon, onDeleteCoupon, suppliers, supplierWithdrawals, onAddSupplier, 
  onAddSupplierWithdrawal, onAddEmployee, onUpdateEmployee, onDeleteEmployee, 
  currentUser, view = 'overview', onViewChange, onAdminUpdateOrder
}) => {
  const [selectedUser, setSelectedUser] = useState<User | null>(null);
  const [selectedSupplier, setSelectedSupplier] = useState<Supplier | null>(null);
  const [isSidebarOpen, setSidebarOpen] = useState(false);

  // Close sidebar when view changes on mobile
  useEffect(() => {
      setSidebarOpen(false);
  }, [view]);

  const setView = (newView: AdminView) => {
      if (onViewChange) {
          onViewChange(newView);
      }
  };

  // --- Header Config Logic ---
  // We will utilize the main App header for the mobile toggle mainly, 
  // but the dashboard has its own layout now.
  useEffect(() => {
      setHeaderConfig({
          title: 'لوحة التحكم',
          showBack: false, // We use internal navigation
      });
      return () => setHeaderConfig(null);
  }, [setHeaderConfig]);


  const adminUnreadTicketsCount = useMemo(() => {
    return tickets.filter(ticket => {
        const lastMessage = ticket.messages[ticket.messages.length - 1];
        return lastMessage && !lastMessage.senderId.includes('admin');
    }).length;
  }, [tickets]);

  const pendingWithdrawalsCount = useMemo(() => {
    return withdrawalRequests.filter(r => r.status === 'pending').length;
  }, [withdrawalRequests]);

  const pendingOrdersCount = useMemo(() => {
    return orders.filter(o => o.status === 'under_implementation').length;
  }, [orders]);

  const allMenuItems = [
    { label: 'نظرة عامة', view: 'overview' as AdminView, icon: LayoutDashboardIcon },
    { label: 'الطلبات', view: 'orders' as AdminView, icon: ClipboardListIcon, badgeCount: pendingOrdersCount },
    { label: 'المنتجات', view: 'products' as AdminView, icon: BoxOpenIcon },
    { label: 'التذاكر', view: 'tickets' as AdminView, icon: TicketIcon, badgeCount: adminUnreadTicketsCount },
    { label: 'السحوبات', view: 'withdrawals' as AdminView, icon: MoneyBillTransferIcon, badgeCount: pendingWithdrawalsCount },
    { label: 'المستخدمين', view: 'users' as AdminView, icon: UsersGearIcon },
    { label: 'الموردين', view: 'suppliers' as AdminView, icon: HandshakeIcon },
    { label: 'الموظفين', view: 'employees' as AdminView, icon: IdCardIcon },
    { label: 'الكوبونات', view: 'coupons' as AdminView, icon: TagIcon },
    { label: 'إرسال إشعار', view: 'notifications' as AdminView, icon: BellIcon },
    { label: 'الإعدادات', view: 'settings' as AdminView, icon: PaletteIcon },
  ];

  const menuItems = useMemo(() => {
      if (!currentUser?.permissions || currentUser.permissions.length === 0) {
          return allMenuItems;
      }
      return allMenuItems.filter(item => 
          currentUser.permissions?.includes(item.view) || item.view === 'overview' // Always show overview
      );
  }, [currentUser, allMenuItems]);

  // Handle Internal Routing Logic for Detail Views
  const handleUserClick = (user: User) => { setSelectedUser(user); setView('userDetails'); };
  const handleBackToUsers = () => { setSelectedUser(null); setView('users'); };
  const handleSupplierClick = (supplier: Supplier) => { setSelectedSupplier(supplier); setView('supplierDetails'); };
  const handleBackToSuppliers = () => { setSelectedSupplier(null); setView('suppliers'); };

  const userOrders = useMemo(() => selectedUser ? orders.filter(o => o.user_id === selectedUser.id) : [], [orders, selectedUser]);
  const userCustomers = useMemo(() => selectedUser ? customers.filter(c => c.user_id === selectedUser.id) : [], [customers, selectedUser]);
  const userWithdrawals = useMemo(() => selectedUser ? withdrawalRequests.filter(w => w.user_id === selectedUser.id) : [], [withdrawalRequests, selectedUser]);
  const employeesList = useMemo(() => users.filter(u => u.is_admin && u.permissions && u.permissions.length > 0), [users]);

  const renderContent = () => {
    // Permission Check
    if (view !== 'dashboard' && view !== 'overview' && currentUser?.permissions && currentUser.permissions.length > 0 && !currentUser.permissions.includes(view)) {
        if (!(view === 'userDetails' && currentUser.permissions.includes('users')) && 
            !(view === 'supplierDetails' && currentUser.permissions.includes('suppliers'))) {
             return (
                <div className="flex flex-col items-center justify-center h-full text-center p-10">
                    <div className="w-20 h-20 bg-red-100 rounded-full flex items-center justify-center mb-4"><XMarkIcon className="w-10 h-10 text-red-500"/></div>
                    <h3 className="text-xl font-bold text-gray-800">صلاحيات محدودة</h3>
                    <p className="text-gray-500 mt-2">ليس لديك صلاحية للوصول لهذا القسم.</p>
                </div>
             );
        }
    }

    if (view === 'userDetails' && selectedUser) {
        return <AdminUserDetailsPage user={selectedUser} userOrders={userOrders} userCustomers={userCustomers} userWithdrawals={userWithdrawals} onOrderClick={onAdminOrderClick} onBack={handleBackToUsers} addNotification={addNotification} setHeaderConfig={setHeaderConfig} />;
    }
    if (view === 'supplierDetails' && selectedSupplier) {
        return <AdminSupplierDetailsPage supplier={selectedSupplier} products={products} orders={orders} withdrawals={supplierWithdrawals.filter(sw => sw.supplierId === selectedSupplier.id)} onAddWithdrawal={onAddSupplierWithdrawal} setHeaderConfig={setHeaderConfig} onBack={handleBackToSuppliers} />;
    }

    switch (view) {
        case 'dashboard': // Fallback alias
        case 'overview': return <AdminDashboardOverviewView users={users} orders={orders} />;
        case 'products': return <AdminProductsMainView products={products} onAddProduct={onAddProduct} onUpdateProduct={onUpdateProduct} onDeleteProduct={onDeleteProduct} orders={orders} categories={categories} suppliers={suppliers} setHeaderConfig={setHeaderConfig} onBackToAdminDashboardMenu={() => {}} />;
        case 'orders': return <AdminOrdersView orders={orders} onUpdateOrderStatus={onUpdateOrderStatus} onAdminOrderClick={onAdminOrderClick} addNotification={addNotification} setHeaderConfig={setHeaderConfig} onAdminUpdateOrder={onAdminUpdateOrder} />;
        case 'users': return <AdminUsersView users={users} onDeleteUser={onDeleteUser} onUserClick={handleUserClick} />;
        case 'suppliers': return <AdminSuppliersView suppliers={suppliers} onAddSupplier={onAddSupplier} onSupplierClick={handleSupplierClick} setHeaderConfig={setHeaderConfig} />;
        case 'employees': return <AdminEmployeesView employees={employeesList} onAddEmployee={onAddEmployee} onUpdateEmployee={onUpdateEmployee} onDeleteEmployee={onDeleteEmployee} setHeaderConfig={setHeaderConfig} />;
        case 'withdrawals': return <AdminWithdrawalsView withdrawalRequests={withdrawalRequests} onProcessWithdrawal={onProcessWithdrawal} users={users} orders={orders} />;
        case 'tickets': return <AdminTicketsView tickets={tickets} onUpdateTicketThreadStatus={onUpdateTicketThreadStatus} onAddTicketMessage={onAddTicketMessage} onOpenTicketChat={onOpenTicketChat} addNotification={addNotification} setHeaderConfig={setHeaderConfig} />;
        case 'coupons': return <AdminCouponsView coupons={coupons} onAddCoupon={onAddCoupon} onUpdateCoupon={onUpdateCoupon} onDeleteCoupon={onDeleteCoupon} addNotification={addNotification} setHeaderConfig={setHeaderConfig} />;
        case 'settings': return <div className="p-6"><AdminSiteSettingsView faqItems={faqItems} siteSettings={siteSettings} onSetFaqItems={onSetFaqItems} onUpdateSiteSettings={onUpdateSiteSettings} categories={categories} onSetCategories={onSetCategories}/></div>;
        case 'notifications': return <AdminNotificationsSender addNotification={addNotification} />;
        default: return <div>جاري التحميل...</div>;
    }
  };

  const currentViewLabel = useMemo(() => {
      return allMenuItems.find(i => i.view === view)?.label || 'لوحة التحكم';
  }, [view]);

  return (
    <div className="flex h-full bg-gray-50 dark:bg-slate-900 relative text-right font-cairo">
        {/* Mobile Overlay */}
        {isSidebarOpen && (
            <div 
                className="fixed inset-0 bg-black/60 backdrop-blur-sm z-40 md:hidden" 
                onClick={() => setSidebarOpen(false)}
            />
        )}

        {/* Sidebar Navigation */}
        <aside 
            className={`
                fixed top-0 right-0 bottom-0 w-72 bg-white dark:bg-gray-800 z-50 flex flex-col border-l border-gray-100 dark:border-gray-700 shadow-2xl md:shadow-none transition-transform duration-300 ease-in-out md:translate-x-0 md:static md:h-full
                ${isSidebarOpen ? 'translate-x-0' : 'translate-x-full'}
            `}
        >
            {/* Sidebar Header */}
            <div className="p-6 border-b border-gray-100 dark:border-gray-700 flex items-center justify-between">
                <div className="flex items-center gap-3">
                    <div className="w-10 h-10 bg-primary/10 rounded-xl flex items-center justify-center text-primary">
                        <BoxOpenIcon className="w-6 h-6" />
                    </div>
                    <div>
                        <h1 className="font-extrabold text-xl text-gray-800 dark:text-white">إلك ستور</h1>
                        <p className="text-xs text-gray-500 dark:text-gray-400">لوحة التحكم</p>
                    </div>
                </div>
                <button onClick={() => setSidebarOpen(false)} className="md:hidden p-2 text-gray-400 hover:text-red-500">
                    <XMarkIcon className="w-6 h-6" />
                </button>
            </div>

            {/* Menu Items */}
            <div className="flex-1 overflow-y-auto p-4 space-y-1">
                {menuItems.map(item => (
                    <SidebarItem 
                        key={item.view}
                        icon={item.icon}
                        label={item.label}
                        isActive={view === item.view}
                        onClick={() => setView(item.view)}
                        badgeCount={item.badgeCount}
                    />
                ))}
            </div>

            {/* User Profile / Logout */}
            <div className="p-4 border-t border-gray-100 dark:border-gray-700">
                <div className="flex items-center gap-3 p-3 rounded-xl bg-gray-50 dark:bg-gray-700/50 mb-2">
                    <div className="w-10 h-10 rounded-full bg-white dark:bg-gray-600 flex items-center justify-center text-gray-400 shadow-sm">
                        <UsersGearIcon className="w-5 h-5" />
                    </div>
                    <div className="overflow-hidden">
                        <p className="font-bold text-sm text-gray-800 dark:text-white truncate">{currentUser?.name}</p>
                        <p className="text-xs text-gray-500 dark:text-gray-400 truncate">{currentUser?.email}</p>
                    </div>
                </div>
            </div>
        </aside>

        {/* Main Content Area */}
        <main className="flex-1 flex flex-col h-full overflow-hidden relative">
            {/* Mobile Header (Visible only on small screens) */}
            <div className="md:hidden flex items-center justify-between p-4 bg-white dark:bg-gray-800 border-b border-gray-100 dark:border-gray-700 flex-shrink-0">
                <h2 className="font-bold text-lg dark:text-gray-100">{currentViewLabel}</h2>
                <button 
                    onClick={() => setSidebarOpen(true)}
                    className="p-2 bg-gray-100 dark:bg-gray-700 rounded-lg text-gray-600 dark:text-gray-300"
                >
                    <MenuIcon className="w-6 h-6" />
                </button>
            </div>

            {/* Content View */}
            <div className="flex-1 overflow-y-auto no-scrollbar">
                {renderContent()}
            </div>
        </main>
    </div>
  );
};

export default AdminDashboardPage;

import React, { useState, useEffect, useMemo } from 'react';
import { Product, Category } from '../../types';
import { PlusIcon, TrashIcon, XMarkIcon, CameraIcon, CubesStackIcon, CalculatorIcon } from '../common/icons';
import { HeaderConfig } from '../../App';

interface AdminProductEditPageProps {
  productToEdit?: Product | null;
  onSave: (product: Product | Omit<Product, 'id'>) => void;
  onCancel: () => void;
  onDeleteProduct: (productId: string) => void; 
  categories: Category[];
  setHeaderConfig: (config: HeaderConfig | null) => void;
}

const AdminProductEditPage: React.FC<AdminProductEditPageProps> = ({ productToEdit, onSave, onCancel, onDeleteProduct, categories: dynamicCategories, setHeaderConfig }) => {
  // Basic Info
  const [name, setName] = useState('');
  const [imageUrls, setImageUrls] = useState<string[]>([]);

  // Series Configuration
  const [seriesCount, setSeriesCount] = useState<number>(0);
  const [seriesSizes, setSeriesSizes] = useState('');
  const [stock, setStock] = useState<number>(0); // Total Series Stock

  // Pricing
  const [price, setPrice] = useState<number>(0); // Wholesale Price
  const [minSellPrice, setMinSellPrice] = useState<number>(0);
  const [maxSellPrice, setMaxSellPrice] = useState<number>(0);

  // Marketing & Categorization
  const [promo, setPromo] = useState('');
  const [description, setDescription] = useState('');
  const [marketingDescription, setMarketingDescription] = useState('');
  const [category, setCategory] = useState('');
  const [subcategory, setSubcategory] = useState('');
  const [telegramUrl, setTelegramUrl] = useState('');
  const [detailsList, setDetailsList] = useState<{key: string, value: string}[]>([]);
  const [tags, setTags] = useState<string[]>([]);

  // Derived Calculations
  const costPerPiece = useMemo(() => {
      if (seriesCount > 0 && price > 0) {
          return Math.round(price / seriesCount);
      }
      return 0;
  }, [price, seriesCount]);

  const minProfit = useMemo(() => {
      if (minSellPrice > 0 && price > 0) {
          return minSellPrice - price;
      }
      return 0;
  }, [minSellPrice, price]);

  useEffect(() => {
    if (productToEdit) {
      setName(productToEdit.name);
      setPrice(productToEdit.price);
      setMinSellPrice(productToEdit.min_sell_price);
      setMaxSellPrice(productToEdit.max_sell_price);
      setPromo(productToEdit.promo);
      setDescription(productToEdit.description || '');
      setMarketingDescription(productToEdit.marketing_description || '');
      setImageUrls(productToEdit.image_urls || []);
      setCategory(productToEdit.category || '');
      setSubcategory(productToEdit.subcategory || '');
      setTelegramUrl(productToEdit.telegramUrl || '');
      setTags(productToEdit.tags || []);

      // Load Series Data
      setSeriesCount(productToEdit.series_count || 0);
      setSeriesSizes(productToEdit.series_sizes || '');
      setStock(productToEdit.stock || 0);

      // Convert details object to array
      if (productToEdit.details) {
          const dList = Object.entries(productToEdit.details).map(([key, value]) => ({ key, value }));
          setDetailsList(dList.length > 0 ? dList : [{key: '', value: ''}]);
      } else {
          setDetailsList([{key: '', value: ''}]);
      }

    } else {
      // Reset form for new product
      setName('');
      setPrice(0);
      setMinSellPrice(0);
      setMaxSellPrice(0);
      setPromo('');
      setDescription('');
      setMarketingDescription('');
      setImageUrls([]);
      setCategory('');
      setSubcategory('');
      setTelegramUrl('');
      setTags([]);

      setSeriesCount(0);
      setSeriesSizes('');
      setStock(0);
      setDetailsList([{key: '', value: ''}]);
    }
  }, [productToEdit]);

  useEffect(() => {
    setHeaderConfig({
        title: productToEdit ? 'تعديل المنتج' : 'إضافة منتج جديد',
        showBack: true,
        onBack: onCancel,
    });
    return () => setHeaderConfig(null);
  }, [productToEdit, onCancel, setHeaderConfig]);

  const handlePriceChange = (field: 'price' | 'min' | 'max', val: number) => {
    let newPrice = price;
    let newMin = minSellPrice;
    let newMax = maxSellPrice;

    if (field === 'price') { setPrice(val); newPrice = val; }
    if (field === 'min') { setMinSellPrice(val); newMin = val; }
    if (field === 'max') { setMaxSellPrice(val); newMax = val; }

    // Smart Promo Logic
    if (newPrice > 0 && newMin > 0) {
        const profit = newMin - newPrice;
        if (profit > 0) {
            let autoPromo = `اربح ${profit.toLocaleString()} د.ع`;
            if (newMax > newMin) {
                autoPromo += ' أو أكثر';
            }
            setPromo(autoPromo);
        }
    }
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
        const reader = new FileReader();
        reader.onloadend = () => {
            setImageUrls(prev => [...prev, reader.result as string]);
        };
        reader.readAsDataURL(file);
    }
  };

  const handleRemoveImage = (indexToRemove: number) => {
    setImageUrls(prev => prev.filter((_, index) => index !== indexToRemove));
  }

  const handleTagChange = (tag: string, checked: boolean) => {
      if (checked) {
          setTags(prev => [...prev, tag]);
      } else {
          setTags(prev => prev.filter(t => t !== tag));
      }
  };

  // Details Handler
  const handleDetailChange = (index: number, field: 'key' | 'value', value: string) => {
      const newList = [...detailsList];
      newList[index] = { ...newList[index], [field]: value };
      setDetailsList(newList);
  };

  const addDetailRow = () => {
      setDetailsList([...detailsList, { key: '', value: '' }]);
  };

  const removeDetailRow = (index: number) => {
      if (detailsList.length > 1) {
          setDetailsList(detailsList.filter((_, i) => i !== index));
      } else {
          setDetailsList([{ key: '', value: '' }]);
      }
  };


  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    // Validation
    if (!name || price <= 0 || imageUrls.length === 0 || !category) {
        alert('يرجى ملء الاسم، السعر، الفئة، وإضافة صورة واحدة على الأقل.');
        return;
    }

    if (minSellPrice <= price) {
        alert('سعر البيع يجب أن يكون أكبر من سعر الجملة.');
        return;
    }

    if (maxSellPrice < minSellPrice) {
        alert('أعلى سعر بيع يجب أن يكون أكبر من أو يساوي أقل سعر بيع.');
        return;
    }

    // Series Validation
    if (seriesCount <= 0 || !seriesSizes || stock < 0) {
        alert('يرجى تعبئة تفاصيل السيرية (العدد، القياسات، والمخزون) بشكل صحيح.');
        return;
    }

    // Convert detailsList to object
    const detailsObject: Record<string, string> = {};
    detailsList.forEach(item => {
        if (item.key.trim() && item.value.trim()) {
            detailsObject[item.key.trim()] = item.value.trim();
        }
    });

    const productData: any = { 
        name, 
        brand: '', 
        price, 
        min_sell_price: minSellPrice, 
        max_sell_price: maxSellPrice,
        promo, 
        description,
        marketing_description: marketingDescription,
        image_urls: imageUrls, 
        category, 
        subcategory,
        telegramUrl,
        tags,
        details: Object.keys(detailsObject).length > 0 ? detailsObject : undefined,
        // Series Data
        series_count: seriesCount,
        series_sizes: seriesSizes,
        stock: stock
    };

    if (productToEdit) {
      onSave({ ...productData, id: productToEdit.id });
    } else {
      onSave(productData);
    }
  };

  const handleDeleteClick = () => {
    if (productToEdit && window.confirm(`هل أنت متأكد من حذف المنتج "${productToEdit.name}"؟`)) {
        onDeleteProduct(productToEdit.id);
        onCancel(); 
    }
  };

  const categoriesToDisplay = useMemo(() => {
      return dynamicCategories.filter(c => c.name !== 'الكل' && c.name !== 'جديد' && !c.parentId);
  }, [dynamicCategories]);

  const subcategoriesToDisplay = useMemo(() => {
      const selectedCat = dynamicCategories.find(c => c.name === category);
      if(!selectedCat) return [];
      return dynamicCategories.filter(c => c.parentId === selectedCat.id);
  }, [category, dynamicCategories]);

  return (
    <div className="p-4 dark:bg-slate-900 pb-32"> 
      <form onSubmit={handleSubmit} className="space-y-6 max-w-2xl mx-auto"> 

        {/* SECTION 1: IMAGES & BASIC INFO */}
        <div className="bg-white dark:bg-gray-800 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700 p-4">
            <h3 className="font-bold text-gray-800 dark:text-gray-100 mb-4 border-b dark:border-gray-700 pb-2">الصور والاسم</h3>

            <div className="space-y-4">
                {/* Images */}
                <div className="grid grid-cols-4 gap-2">
                    {imageUrls.map((url, index) => (
                        <div key={index} className="relative group aspect-square">
                            <img src={url} className="w-full h-full object-cover rounded-lg bg-gray-100 dark:bg-gray-700 shadow-sm" loading="lazy" />
                            <button type="button" onClick={() => handleRemoveImage(index)} className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full w-6 h-6 flex items-center justify-center shadow-md transition-transform hover:scale-110">
                                <XMarkIcon className="w-3 h-3" />
                            </button>
                        </div>
                    ))}
                    {imageUrls.length < 5 && (
                        <label htmlFor="image-upload" className="flex flex-col justify-center items-center w-full h-full border-2 border-primary/30 border-dashed rounded-lg cursor-pointer bg-primary/5 hover:bg-primary/10 transition-colors aspect-square">
                            <CameraIcon className="w-6 h-6 text-primary mb-1" />
                            <span className="text-[10px] text-primary font-bold">أضف صورة</span>
                            <input id="image-upload" type="file" className="hidden" accept="image/png, image/jpeg" onChange={handleImageUpload} />
                        </label>
                    )}
                </div>

                {/* Name */}
                <div>
                    <label className="text-xs font-bold text-gray-500 dark:text-gray-400 block text-right mb-1">اسم المنتج</label>
                    <input type="text" placeholder="مثال: قميص رجالي قطن" value={name} onChange={e => setName(e.target.value)} required className="w-full p-3 border dark:border-gray-600 rounded-xl text-right bg-gray-50 dark:bg-gray-700 dark:text-white focus:ring-2 focus:ring-primary/50 outline-none font-bold" />
                </div>
            </div>
        </div>

        {/* SECTION 2: SERIES CONFIGURATION (THE CORE) */}
        <div className="bg-blue-50 dark:bg-blue-900/10 rounded-2xl border border-blue-200 dark:border-blue-800 p-4">
            <div className="flex justify-between items-center mb-4 border-b border-blue-200 dark:border-blue-800 pb-2">
                <label className="text-base font-extrabold text-blue-800 dark:text-blue-300 flex items-center gap-2">
                    <CubesStackIcon className="w-5 h-5" />
                    تكوين السيرية (الباكيت)
                </label>
            </div>

            <div className="space-y-4">
                <div className="grid grid-cols-2 gap-4">
                    <div>
                        <label className="text-xs font-bold text-blue-700 dark:text-blue-300 block text-right mb-1">عدد القطع في السيرية</label>
                        <input 
                            type="number" 
                            value={seriesCount || ''} 
                            onChange={e => setSeriesCount(Number(e.target.value))} 
                            className="w-full p-3 border border-blue-200 dark:border-blue-700 rounded-xl text-center bg-white dark:bg-gray-800 dark:text-white font-extrabold text-lg focus:ring-2 focus:ring-blue-400 outline-none" 
                            min="1"
                            placeholder="0"
                        />
                    </div>
                    <div>
                        <label className="text-xs font-bold text-blue-700 dark:text-blue-300 block text-right mb-1">المخزون (عدد السيريات)</label>
                        <input 
                            type="number" 
                            value={stock || ''} 
                            onChange={e => setStock(Number(e.target.value))} 
                            className="w-full p-3 border border-blue-200 dark:border-blue-700 rounded-xl text-center bg-white dark:bg-gray-800 dark:text-white font-extrabold text-lg focus:ring-2 focus:ring-blue-400 outline-none" 
                            min="0"
                            placeholder="0"
                        />
                    </div>
                </div>

                <div>
                    <label className="text-xs font-bold text-blue-700 dark:text-blue-300 block text-right mb-1">وصف القياسات داخل السيرية</label>
                    <input 
                        type="text" 
                        placeholder="مثال: S:2, M:4, L:4, XL:2" 
                        value={seriesSizes} 
                        onChange={e => setSeriesSizes(e.target.value)} 
                        className="w-full p-3 border border-blue-200 dark:border-blue-700 rounded-xl text-right bg-white dark:bg-gray-800 dark:text-white placeholder:text-gray-400 focus:ring-2 focus:ring-blue-400 outline-none" 
                    />
                </div>
            </div>
        </div>

        {/* SECTION 3: PRICING & PROFIT */}
        <div className="bg-white dark:bg-gray-800 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700 p-4">
            <h3 className="font-bold text-gray-800 dark:text-gray-100 mb-4 border-b dark:border-gray-700 pb-2 flex items-center gap-2">
                <CalculatorIcon className="w-5 h-5 text-green-500" />
                التسعير والأرباح
            </h3>

            <div className="space-y-4">
                {/* Wholesale & Cost Per Piece */}
                <div className="grid grid-cols-2 gap-4 bg-gray-50 dark:bg-gray-700/30 p-3 rounded-xl">
                    <div>
                        <label className="text-xs font-bold text-gray-600 dark:text-gray-300 block text-right mb-1">سعر الجملة (للسيرية)</label>
                        <input 
                            type="number" 
                            placeholder="0" 
                            value={price || ''} 
                            onChange={e => handlePriceChange('price', Number(e.target.value))} 
                            required 
                            className="w-full p-3 border border-gray-300 dark:border-gray-600 rounded-xl text-center bg-white dark:bg-gray-800 dark:text-white font-extrabold text-lg focus:ring-2 focus:ring-primary outline-none" 
                            min="0" 
                        />
