const ChangePasswordModal: React.FC<{
    onClose: () => void;
    onSave: (newPass: string) => void;
}> = ({ onClose, onSave }) => {
    const [currentPass, setCurrentPass] = useState('');
    const [newPass, setNewPass] = useState('');
