// --- Helper Components for Charts (Custom SVG/CSS implementation to avoid external libs) ---

const TinyLineChart: React.FC<{ data: number[], color: string }> = ({ data, color }) => {
    const max = Math.max(...data, 1);
    const points = data.map((val, i) => {
        const x = (i / (data.length - 1)) * 100;
        const y = 100 - (val / max) * 100;
        return `${x},${y}`;
    }).join(' ');

    return (
        <svg viewBox="0 0 100 100" className="w-full h-16 overflow-visible" preserveAspectRatio="none">
            <polyline
                fill="none"
                stroke="currentColor"
                strokeWidth="3"
                points={points}
                className={color}
                strokeLinecap="round"
                strokeLinejoin="round"
            />
            <polygon 
                fill="currentColor" 
                points={`0,100 ${points} 100,100`} 
                className={`${color} opacity-10`} 
            />
        </svg>
    );
};

const ProgressBar: React.FC<{ value: number, max: number, colorClass: string }> = ({ value, max, colorClass }) => {
    const width = Math.min(100, Math.max(0, (value / max) * 100));
    return (
        <div className="h-2 w-full bg-gray-100 dark:bg-gray-700 rounded-full overflow-hidden">
            <div className={`h-full rounded-full ${colorClass}`} style={{ width: `${width}%` }}></div>
        </div>
    );
};

