        purple: { bg: 'bg-purple-50 dark:bg-purple-900/10', text: 'text-purple-600 dark:text-purple-400', border: 'border-purple-100 dark:border-purple-800' },
        orange: { bg: 'bg-orange-50 dark:bg-orange-900/10', text: 'text-orange-600 dark:text-orange-400', border: 'border-orange-100 dark:border-orange-800' },
    };
    const t = themes[color];

    return (
        <div className={`bg-white dark:bg-gray-800 rounded-3xl p-5 border ${t.border} shadow-sm relative overflow-hidden group`}>
