const AdminDashboardOverviewView: React.FC<AdminDashboardOverviewViewProps> = ({ users, orders }) => {
    const [timeRange, setTimeRange] = useState<'7days' | '30days' | 'all'>('30days');

    // --- 1. Data Processing Engine ---

    // Filter orders based on TimeRange
    const filteredOrders = useMemo(() => {
        const now = new Date();
        if (timeRange === 'all') return orders;

        const days = timeRange === '7days' ? 7 : 30;
        const cutoff = new Date(now.setDate(now.getDate() - days));

        return orders.filter(o => new Date(o.created_at) >= cutoff);
    }, [orders, timeRange]);

    // Financials
    const stats = useMemo(() => {
        let revenue = 0;
        let profit = 0;
        let completedCount = 0;
        let itemsSold = 0;

        filteredOrders.forEach(o => {
            if (o.status !== 'cancelled' && o.status !== 'rejected') {
                revenue += o.total_cost; // or actual revenue logic
                if (o.status === 'completed') {
                    profit += (o.profit - (o.service_fee || 0));
                    completedCount++;
                    itemsSold += o.items.reduce((s, i) => s + i.quantity, 0);
                }
            }
        });

        return { revenue, profit, completedCount, totalCount: filteredOrders.length, itemsSold };
    }, [filteredOrders]);

    // Chart Data (Daily Sales for the last N days)
    const chartData = useMemo(() => {
        const daysMap = new Map<string, number>();
        const daysCount = timeRange === '7days' ? 7 : (timeRange === '30days' ? 30 : 12); // 12 months for 'all' simplified

        // Initialize map
        for (let i = 0; i < daysCount; i++) {
            const d = new Date();
            d.setDate(d.getDate() - i);
            const key = d.toISOString().split('T')[0];
            daysMap.set(key, 0);
        }

        filteredOrders.forEach(o => {
            const key = new Date(o.created_at).toISOString().split('T')[0];
            if (daysMap.has(key) && o.status === 'completed') {
                daysMap.set(key, (daysMap.get(key) || 0) + (o.profit));
            }
        });

        // Reverse to show oldest to newest
        return Array.from(daysMap.values()).reverse();
    }, [filteredOrders, timeRange]);

    // Status Distribution
    const statusStats = useMemo(() => {
        const counts = {
            completed: 0,
            pending: 0,
            cancelled: 0,
            shipping: 0
        };

        filteredOrders.forEach(o => {
            if (o.status === 'completed') counts.completed++;
            else if (['cancelled', 'rejected'].includes(o.status)) counts.cancelled++;
            else if (['shipped', 'partially_delivered'].includes(o.status)) counts.shipping++;
            else counts.pending++;
        });

        return counts;
    }, [filteredOrders]);

    // Top Governorates
    const governorateStats = useMemo(() => {
        const map: Record<string, number> = {};
        filteredOrders.forEach(o => {
            if(o.customer?.governorate) {
                map[o.customer.governorate] = (map[o.customer.governorate] || 0) + 1;
            }
        });
        return Object.entries(map).sort((a,b) => b[1] - a[1]).slice(0, 5);
    }, [filteredOrders]);

    // Top Marketers
    const topMarketers = useMemo(() => {
        const map: Record<string, {name: string, profit: number, orders: number}> = {};
        filteredOrders.forEach(o => {
            if (o.status === 'completed') {
                if (!map[o.user_id]) {
                    const u = users.find(user => user.id === o.user_id);
                    map[o.user_id] = { name: u?.name || 'مجهول', profit: 0, orders: 0 };
                }
                map[o.user_id].profit += o.profit;
                map[o.user_id].orders += 1;
            }
        });
        return Object.values(map).sort((a,b) => b.profit - a.profit).slice(0, 5);
    }, [filteredOrders, users]);

    // --- Render ---

    return (
        <div className="p-6 space-y-6 dark:bg-slate-900 pb-20 font-cairo">

            {/* 1. Header & Filters */}
            <div className="flex flex-col md:flex-row justify-between items-center gap-4">
                <div>
                    <h1 className="text-2xl font-bold text-gray-900 dark:text-white">لوحة المعلومات</h1>
                    <p className="text-sm text-gray-500 dark:text-gray-400 mt-1">نظرة شاملة على أداء المتجر والمبيعات</p>
                </div>
                <div className="flex bg-white dark:bg-gray-800 p-1 rounded-xl shadow-sm border dark:border-gray-700">
                    {[
                        { k: '7days', l: '7 أيام' },
                        { k: '30days', l: '30 يوم' },
                        { k: 'all', l: 'الكل' }
                    ].map(t => (
                        <button
                            key={t.k}
                            onClick={() => setTimeRange(t.k as any)}
                            className={`px-4 py-2 rounded-lg text-sm font-bold transition-all ${timeRange === t.k ? 'bg-gray-100 dark:bg-gray-700 text-primary' : 'text-gray-500 hover:text-gray-700 dark:text-gray-400'}`}
                        >
                            {t.l}
                        </button>
                    ))}
                </div>
            </div>

            {/* 2. Key Metrics Cards */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
                <AnalyticsCard 
                    title="صافي الأرباح" 
                    value={`${stats.profit.toLocaleString()}`} 
                    subValue="د.ع (طلبات مكتملة)"
                    icon={WalletIcon} 
                    color="green" 
                    data={chartData}
                    trend="up"
                    trendValue="مؤشر"
                />
                <AnalyticsCard 
                    title="إجمالي الإيرادات" 
                    value={`${stats.revenue.toLocaleString()}`} 
                    subValue="د.ع (قيمة الطلبات)"
                    icon={ChartUpIcon} 
                    color="blue" 
                    // Simulate slightly different data for visual variety
                    data={chartData.map(x => x * 1.5)} 
                />
                <AnalyticsCard 
                    title="الطلبات النشطة" 
                    value={`${stats.totalCount}`} 
                    subValue="طلب في الفترة المحددة"
                    icon={ClipboardListIcon} 
                    color="purple" 
                    trend="neutral"
                    trendValue="نشاط"
                />
                <AnalyticsCard 
                    title="قاعدة المستخدمين" 
                    value={`${users.length}`} 
                    subValue="مسوق مسجل"
                    icon={UsersIcon} 
                    color="orange" 
                />
            </div>

            {/* 3. Middle Section: Status Distribution & Geography */}
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

                {/* Status Breakdown */}
                <div className="bg-white dark:bg-gray-800 rounded-3xl p-6 border border-gray-100 dark:border-gray-700 shadow-sm lg:col-span-2">
                    <h3 className="font-bold text-gray-800 dark:text-gray-100 mb-6 flex items-center gap-2">
                        <BoxOpenIcon className="w-5 h-5 text-gray-500" />
                        حالة الطلبات
                    </h3>
                    <div className="space-y-6">
                        <div>
                            <div className="flex justify-between text-sm mb-2 font-semibold">
                                <span className="text-green-600 dark:text-green-400">مكتملة ({statusStats.completed})</span>
                                <span className="text-gray-500">{Math.round((statusStats.completed / stats.totalCount) * 100 || 0)}%</span>
                            </div>
                            <ProgressBar value={statusStats.completed} max={stats.totalCount} colorClass="bg-green-500" />
                        </div>
                        <div>
                            <div className="flex justify-between text-sm mb-2 font-semibold">
                                <span className="text-blue-600 dark:text-blue-400">جاري التوصيل ({statusStats.shipping})</span>
                                <span className="text-gray-500">{Math.round((statusStats.shipping / stats.totalCount) * 100 || 0)}%</span>
                            </div>
                            <ProgressBar value={statusStats.shipping} max={stats.totalCount} colorClass="bg-blue-500" />
                        </div>
                        <div>
                            <div className="flex justify-between text-sm mb-2 font-semibold">
                                <span className="text-yellow-600 dark:text-yellow-400">قيد المعالجة ({statusStats.pending})</span>
                                <span className="text-gray-500">{Math.round((statusStats.pending / stats.totalCount) * 100 || 0)}%</span>
                            </div>
                            <ProgressBar value={statusStats.pending} max={stats.totalCount} colorClass="bg-yellow-500" />
                        </div>
                        <div>
                            <div className="flex justify-between text-sm mb-2 font-semibold">
                                <span className="text-red-600 dark:text-red-400">ملغاة / راجعة ({statusStats.cancelled})</span>
                                <span className="text-gray-500">{Math.round((statusStats.cancelled / stats.totalCount) * 100 || 0)}%</span>
                            </div>
                            <ProgressBar value={statusStats.cancelled} max={stats.totalCount} colorClass="bg-red-500" />
                        </div>
                    </div>
                </div>

                {/* Geography / Governorates */}
                <div className="bg-white dark:bg-gray-800 rounded-3xl p-6 border border-gray-100 dark:border-gray-700 shadow-sm">
                    <h3 className="font-bold text-gray-800 dark:text-gray-100 mb-6 flex items-center gap-2">
                        <MapPinIcon className="w-5 h-5 text-gray-500" />
                        أعلى المحافظات
                    </h3>
                    <div className="space-y-4">
                        {governorateStats.length > 0 ? governorateStats.map(([gov, count], idx) => (
                            <div key={gov} className="flex items-center gap-3">
                                <div className="w-8 h-8 rounded-full bg-gray-100 dark:bg-gray-700 flex items-center justify-center font-bold text-xs text-gray-600 dark:text-gray-300">
                                    {idx + 1}
                                </div>
                                <div className="flex-grow">
                                    <div className="flex justify-between text-sm font-semibold mb-1">
                                        <span className="dark:text-gray-200">{gov}</span>
                                        <span className="text-gray-500">{count} طلب</span>
                                    </div>
                                    <div className="h-1.5 w-full bg-gray-50 dark:bg-gray-900 rounded-full overflow-hidden">
                                        <div className="h-full bg-primary rounded-full opacity-80" style={{ width: `${(count / (governorateStats[0][1] || 1)) * 100}%` }}></div>
                                    </div>
                                </div>
                            </div>
                        )) : (
                            <div className="text-center text-gray-400 py-10">لا توجد بيانات جغرافية كافية</div>
                        )}
                    </div>
                </div>
            </div>

            {/* 4. Top Performers Table */}
            <div className="bg-white dark:bg-gray-800 rounded-3xl overflow-hidden border border-gray-100 dark:border-gray-700 shadow-sm">
                <div className="p-6 border-b dark:border-gray-700 flex justify-between items-center">
                    <h3 className="font-bold text-lg text-gray-800 dark:text-gray-100 flex items-center gap-2">
                        <TrendingUp className="w-5 h-5 text-yellow-500" />
                        أفضل المسوقين أداءً
                    </h3>
                </div>
                <div className="overflow-x-auto">
                    <table className="w-full text-right">
                        <thead className="bg-gray-50 dark:bg-gray-700/50 text-gray-500 dark:text-gray-400 text-xs uppercase font-bold">
                            <tr>
                                <th className="px-6 py-4">المسوق</th>
                                <th className="px-6 py-4">الطلبات المكتملة</th>
                                <th className="px-6 py-4">معدل النجاح</th>
                                <th className="px-6 py-4 text-left">الأرباح المحققة</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-100 dark:divide-gray-700">
                            {topMarketers.length > 0 ? topMarketers.map((marketer, index) => (
                                <tr key={index} className="hover:bg-gray-50 dark:hover:bg-gray-700/30 transition-colors">
                                    <td className="px-6 py-4">
                                        <div className="flex items-center gap-3">
                                            <div className="w-10 h-10 rounded-full bg-gradient-to-tr from-primary to-orange-300 flex items-center justify-center text-white font-bold shadow-sm">
                                                {marketer.name.charAt(0)}
                                            </div>
                                            <div>
                                                <p className="font-bold text-gray-900 dark:text-white text-sm">{marketer.name}</p>
                                                <p className="text-xs text-green-500 font-medium">نشط جداً</p>
                                            </div>
                                        </div>
                                    </td>
                                    <td className="px-6 py-4 text-sm font-bold text-gray-600 dark:text-gray-300">
                                        {marketer.orders}
                                    </td>
                                    <td className="px-6 py-4">
                                        <span className="px-3 py-1 rounded-full text-xs font-bold bg-green-50 text-green-600 dark:bg-green-900/30 dark:text-green-400">
                                            98%
                                        </span>
                                    </td>
                                    <td className="px-6 py-4 text-left">
                                        <span className="font-extrabold text-gray-800 dark:text-white text-base">
                                            {marketer.profit.toLocaleString()} <span className="text-xs text-gray-400">د.ع</span>
                                        </span>
                                    </td>
                                </tr>
                            )) : (
                                <tr>
                                    <td colSpan={4} className="text-center py-8 text-gray-400">لا توجد بيانات كافية لعرض المتصدرين</td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
};

